<script>
var ST=(function(){
  function g(id){return document.getElementById(id);}
  var raw=(g('raw').value||'').replace(/<\/?STATUS>/gi,'').trim();
  var D={}; try{if(raw&&raw[0]==='{')D=JSON.parse(raw);}catch(e){}
  if(D.age!==undefined) D.age=parseInt(D.age,10)||D.age;
  if(D.year!==undefined) D.year=parseInt(D.year,10)||D.year;
  var th=(D.lang==='th');

  var BRANCHES={
    cadet:{img:'evot65.png',en:'Cadet / Recruit',th:'นักเรียนนายร้อย / ทหารฝึก'},
    recruit:{img:'evot65.png',en:'Cadet / Recruit',th:'นักเรียนนายร้อย / ทหารฝึก'},
    survey_corps:{img:'22gmzq.png',en:'Survey Corps',th:'กองพันสำรวจ'},
