    odm:'อุปกรณ์เคลื่อนที่',notEquipped:'ไม่ได้สวมใส่',weapons:'อาวุธ',
    unknown:'ไม่ระบุชื่อ',inheritor:'ผู้สืบทอดในปัจจุบัน',
